package com.babidndn.order;
import jakarta.validation.Valid;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController public class OrderController { private final OrderService service; public OrderController(OrderService service){this.service=service;} @PostMapping("/api/orders") public CustomerOrder create(){return service.createFromCart();} @GetMapping("/api/orders") public List<CustomerOrder> orders(){return service.findAll();} @GetMapping("/api/orders/{id}") public CustomerOrder detail(@PathVariable Long id){return service.findById(id);} @GetMapping("/api/admin/orders") public List<CustomerOrder> adminOrders(){return service.findAll();} @PatchMapping("/api/admin/orders/{id}") public CustomerOrder status(@PathVariable Long id,@Valid @RequestBody OrderStatusRequest request){return service.changeStatus(id,request.status());} }
